#!/usr/bin/env python3
"""Add final 64 facts to reach exactly 470."""

def write_fact(f, level, tru, tkz, pru, pkz, oru, okz, corr, eru, ekz):
    f.write("    (\n")
    f.write(f'        "{level}",\n')
    f.write(f'        "{tru}", "{tkz}",\n')
    f.write(f'        "{pru}",\n')
    f.write(f'        "{pkz}",\n')
    f.write(f'        {oru},\n')
    f.write(f'        {okz},\n')
    f.write(f'        {corr},\n')
    f.write(f'        "{eru}",\n')
    f.write(f'        "{ekz}"\n')
    f.write("    ),\n")

# Remove trailing ]
with open('scripts/facts_world_history.py', 'r') as f:
    content = f.read()
content = content.rstrip()
if content.endswith(']'):
    content = content[:-1]
with open('scripts/facts_world_history.py', 'w') as f:
    f.write(content)

